from flask import Flask, request, jsonify, g
from functools import wraps
from datetime import datetime, timezone, timedelta
import secrets
import hashlib

app = Flask(__name__)

# In production, use a real database
api_keys_db = {}
rate_limit_store = {}  # key_hash -> {count, window_start}


def hash_api_key(key: str) -> str:
    """Hash API keys before storing -- treat them like passwords."""
    return hashlib.sha256(key.encode()).hexdigest()


def require_api_key(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        api_key = request.headers.get('X-API-Key') or request.args.get('api_key')
        if not api_key:
            return jsonify({'error': 'API key required'}), 401

        key_hash = hash_api_key(api_key)
        key_record = api_keys_db.get(key_hash)

        if not key_record:
            return jsonify({'error': 'Invalid API key'}), 401

        if not key_record.get('active', True):
            return jsonify({'error': 'API key has been revoked'}), 401

        # Rate limiting
        now = datetime.now(timezone.utc)
        rate_info = rate_limit_store.get(key_hash, {
            'count': 0,
            'window_start': now
        })

        if (now - rate_info['window_start']) > timedelta(minutes=1):
            rate_info = {'count': 0, 'window_start': now}

        rate_info['count'] += 1
        rate_limit_store[key_hash] = rate_info

        limit = key_record.get('rate_limit', 60)
        if rate_info['count'] > limit:
            return jsonify({
                'error': 'Rate limit exceeded',
                'retry_after': 60
            }), 429

        # Update last used timestamp
        key_record['last_used'] = now.isoformat()

        g.api_key_owner = key_record['owner']
        g.api_key_scopes = key_record.get('scopes', [])
        return f(*args, **kwargs)
    return decorated


@app.route('/api/keys', methods=['POST'])
def create_api_key():
    """Generate a new API key. Show it once -- it cannot be retrieved later."""
    data = request.get_json()
    owner = data.get('owner', '')
    scopes = data.get('scopes', ['read'])

    raw_key = f"myapp_{secrets.token_urlsafe(32)}"
    key_hash = hash_api_key(raw_key)

    api_keys_db[key_hash] = {
        'owner': owner,
        'scopes': scopes,
        'created': datetime.now(timezone.utc).isoformat(),
        'last_used': None,
        'active': True,
        'rate_limit': 60,  # requests per minute
    }

    return jsonify({
        'api_key': raw_key,
        'message': 'Save this key now. It cannot be retrieved later.',
        'scopes': scopes,
    }), 201


@app.route('/api/data', methods=['GET'])
@require_api_key
def get_data():
    if 'read' not in g.api_key_scopes:
        return jsonify({'error': 'Insufficient scope'}), 403
    return jsonify({'data': 'Here is your data', 'owner': g.api_key_owner})

