MAGIC_LINK_BASE_URL = 'https://myapp.com/auth/verify'


def generate_magic_token() -> str:
    return secrets.token_urlsafe(48)


def send_magic_link_email(email: str, link: str):
    """Send the magic link email. Use a real email service in production."""
    # In production, use SendGrid, AWS SES, Postmark, etc.
