@app.route('/api/auth/magic-link', methods=['POST'])
def request_magic_link():
    data = request.get_json()
    email = data.get('email', '').strip().lower()

    if not email:
        return jsonify({'error': 'Email is required'}), 400

    token = generate_magic_token()
    token_hash = hashlib.sha256(token.encode()).hexdigest()

    magic_link_store[token_hash] = {
        'email': email,
        'expires': datetime.now(timezone.utc) + MAGIC_LINK_EXPIRY,
        'used': False,
    }

    link = f"{MAGIC_LINK_BASE_URL}?token={token}"
    send_magic_link_email(email, link)

    # Always return success to prevent email enumeration
    return jsonify({
        'message': 'If that email is registered, you will receive a login link.'
    })


@app.route('/api/auth/verify-magic-link', methods=['GET'])
def verify_magic_link():
    token = request.args.get('token', '')
    if not token:
        return jsonify({'error': 'Token required'}), 400

    token_hash = hashlib.sha256(token.encode()).hexdigest()
    record = magic_link_store.get(token_hash)

    if not record:
        return jsonify({'error': 'Invalid or expired link'}), 401

    if record['used']:
        return jsonify({'error': 'Link already used'}), 401

    if datetime.now(timezone.utc) > record['expires']:
        del magic_link_store[token_hash]
        return jsonify({'error': 'Link expired'}), 401

    # Mark as used (one-time use)
    record['used'] = True

    # Create session for the user
    email = record['email']
    session['user_id'] = email  # In production, look up user ID
    session['email'] = email

    return redirect('/dashboard')

